\begin{theorem}[Threshold phenomenon]
\label{thm:threshold}
Let $h=h(n)\ge0$ and $r_n=(n-1)/(n-1+\theta)$.
\begin{enumerate}
\item If $\Phi_{h(n)-1}(r_n)\to0$, then $q_n(h(n))\to1$.
\item If $\Phi_{h(n)-1}(r_n)\to\infty$, then $q_n(h(n))\to0$.
\end{enumerate}
\end{theorem}

