\begin{lemma}[Explicit formula for $\beta_t(\theta)$]
For any real number $t>1$,
\begin{equation*}
\beta_t(\theta) = \frac{\Gamma(t)\,\Gamma(\theta+1)}{\Gamma(\theta+t)}.
\end{equation*}
\end{lemma}

